#[cfg(test)]
mod tests {
    use super::*;
    use backbone_core::state_machine::StateMachineBehavior;

    #[test]
    fn test_initial_state() {
        let sm = BucketStateMachine::default();
        assert_eq!(sm.current_state(), BucketState::Active);
        assert!(sm.current_state().is_initial());
    }

    #[test]
    fn test_valid_transition() {
        let mut sm = BucketStateMachine { current_state: BucketState::Active };
        assert!(sm.can_transition(BucketTransition::Lock));
        let result = sm.transition(BucketTransition::Lock);
        assert!(result.is_ok());
        assert_eq!(sm.current_state(), BucketState::Readonly);
    }

    #[test]
    fn test_invalid_transition() {
        let mut sm = BucketStateMachine { current_state: BucketState::Active };
        // Unlock is not valid from Active state
        let result = sm.transition(BucketTransition::Unlock);
        assert!(result.is_err());
    }

    #[test]
    fn test_state_parsing() {
        let state: BucketState = "active".parse().unwrap();
        assert_eq!(state, BucketState::Active);
    }

    #[test]
    fn test_available_transitions() {
        let sm = BucketStateMachine::default();
        let available = sm.available_transitions();
        // Should have at least some transitions available from initial state
        assert!(!available.is_empty() || sm.current_state().is_final());
    }
}
